// A feed item-ek kinyerése + dedup a workflow static data alapján.
// Csak az ELSŐ még nem látott (legfrissebb) posztot engedi tovább futásonként,
// hogy ne posztoljon egyszerre 10 cikket az első indításkor.

const input = $input.first().json;

// Ghost/Substack RSS struktúra: rss.channel.item (lehet tömb vagy egyetlen objektum)
let items = input?.rss?.channel?.item ?? [];
if (!Array.isArray(items)) items = [items];

if (items.length === 0) {
  return [];
}

const store = $getWorkflowStaticData('global');
store.seenGuids = store.seenGuids || [];

// A feed legfrissebb elöl jön. Megfordítjuk, hogy időrendben dolgozzuk fel.
const chronological = [...items].reverse();

const freshOnes = [];
for (const it of chronological) {
  const guid = (it.guid && (it.guid['_'] || it.guid)) || it.link;
  if (!guid) continue;
  if (!store.seenGuids.includes(guid)) {
    freshOnes.push({ item: it, guid });
  }
}

if (freshOnes.length === 0) {
  return [];
}

// Csak egyet dolgozunk fel futásonként (a legrégebbi még feldolgozatlant).
const next = freshOnes[0];
const it = next.item;

const title = (it.title && (it.title['_'] || it.title)) || '';
const link = it.link || '';
const pubDate = it.pubDate || '';
// content:encoded vagy description tartalmazza a HTML törzset (paywallnál csak teaser!)
const html = it['content:encoded'] || it.description || '';

return [
  {
    json: {
      guid: next.guid,
      sourceTitle: String(title).trim(),
      sourceUrl: String(link).trim(),
      sourcePubDate: String(pubDate).trim(),
      sourceHtml: String(html)
    }
  }
];

// Slug-lista + a TELJES LLM kérés-body összeállítása JSON.stringify-jal.
// Így a cikk HTML-jében lévő idézőjel/sortörés/backslash sem töri szét a JSON-t.

const files = $input.all();
const slugs = files
  .map(f => f.json.name)
  .filter(n => typeof n === 'string' && n.endsWith('.md'))
  .map(n => n.replace(/\.md$/, ''));

const source = $('Új poszt szűrés (dedup)').first().json;

const system = [
  "Te a Conen Digital (conendigital.hu) magyar szakmai blogjának szerkesztője vagy. A feladatod, hogy egy angol nyelvű szoftverfejlesztői/tech cikk alapján EREDETI, magyar nyelvű FELDOLGOZÁST írj – NEM szó szerinti fordítást. Ez jogilag (szerzői jog) és SEO szempontból (duplikált tartalom elkerülése) is kötelező. A cikk Gergely Orosz 'The Pragmatic Engineer' blogjából származik.",
  "",
  "SZABÁLYOK:",
  "1. Írj egy önálló, magyar nyelvű elemző-összefoglaló cikket (600-1000 szó), ami a forrás fő gondolatait ismerteti, ÉS hozzáteszi a magyar/KKV piaci kontextust vagy a Conen Digital nézőpontját.",
  "2. KÖTELEZŐ forrásmegjelölés: a cikk elején egy bevezető mondat, a végén pedig egy 'Forrás' szekció a teljes eredeti címmel és linkkel: [eredeti cím](forrás URL).",
  "3. Ne másolj le 30 egymást követő szónál többet az eredetiből. Parafrazeálj.",
  "4. Szúrj be 1-3 RELEVÁNS belső linket a megadott meglévő slug-listából, markdown formátumban: [horgonyszöveg](/blog/slug). Csak akkor linkelj, ha tényleg releváns.",
  "5. A 'category' mező ÉRTÉKE KIZÁRÓLAG ezek egyike lehet: EAA, AX-readiness, AI Ops, Site Factory, MCP-Commerce, Case Study, CENTAUR. Válaszd a témához legközelebbit (tech/fejlesztői témánál általában 'AI Ops' vagy 'CENTAUR').",
  "6. A 'tags' 3-6 magyar/angol kulcsszó tömbje.",
  "7. A 'slug' kötőjeles, ékezet nélküli, csak [a-z0-9-], magyar nyelvű.",
  "8. A 'summary' 1-2 mondat, max 155 karakter (meta description).",
  "9. A body markdown legyen: H2 (##) szekciók, **bold**, listák. NE tegyél bele H1-et (a title adja).",
  "",
  "KIMENET: KIZÁRÓLAG egy JSON objektum, mezők: title (string), summary (string), category (string), tags (string tömb), slug (string), readingTime (szám, perc), body_markdown (string)."
].join("\n");

const user = [
  "EREDETI CÍM: " + (source.sourceTitle || ''),
  "",
  "FORRÁS URL: " + (source.sourceUrl || ''),
  "",
  "MEGLÉVŐ POSZT SLUG-OK (belső linkeléshez): " + JSON.stringify(slugs),
  "",
  "EREDETI TARTALOM (HTML, lehet csak részlet/teaser ha fizetős):",
  (source.sourceHtml || '')
].join("\n");

const payload = {
  model: "llama-3.3-70b-versatile",
  temperature: 0.4,
  response_format: { type: "json_object" },
  messages: [
    { role: "system", content: system },
    { role: "user", content: user }
  ]
};

return [
  {
    json: {
      ...source,
      existingSlugs: slugs,
      llmBody: JSON.stringify(payload)
    }
  }
];

// Az LLM JSON válaszának kibontása és a .md fájl tartalom összeállítása.

const resp = $input.first().json;

// OpenAI-kompatibilis válaszstruktúra: choices[0].message.content (string, ami JSON)
let raw = resp?.choices?.[0]?.message?.content ?? '';
let ai;
try {
  ai = JSON.parse(raw);
} catch (e) {
  // Néha kódblokkba csomagolja – próbáljuk kivágni a { ... } részt
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('Az AI válasza nem értelmezhető JSON: ' + raw.slice(0, 300));
  ai = JSON.parse(m[0]);
}

const source = $('Slug lista összeállítás').first().json;

// --- validáció / fallback ---
const VALID_CATEGORIES = ['EAA', 'AX-readiness', 'AI Ops', 'Site Factory', 'MCP-Commerce', 'Case Study', 'CENTAUR'];
let category = VALID_CATEGORIES.includes(ai.category) ? ai.category : 'AI Ops';

function slugify(s) {
  return String(s)
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
}

let slug = ai.slug ? slugify(ai.slug) : slugify(ai.title || source.sourceTitle);
if (!slug) slug = 'pragmatic-' + Date.now();

const tags = Array.isArray(ai.tags) ? ai.tags : [];
const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
const readingTime = Number.isFinite(ai.readingTime) ? ai.readingTime : 6;

// YAML-biztos string escape (idézőjelek)
function yq(s) {
  return '"' + String(s).replace(/\\/g, '\\\\').replace(/"/g, '\\"') + '"';
}

const tagsYaml = tags.map(t => '  - ' + yq(t)).join('\n');

const frontmatter = [
  '---',
  'title: ' + yq(ai.title || source.sourceTitle),
  'summary: ' + yq(ai.summary || ''),
  'publishedAt: ' + today,
  'category: ' + yq(category),
  'tags:',
  tagsYaml,
  'author: "Chris Conen"',
  'readingTime: ' + readingTime,
  'draft: true',
  '---',
  ''
].join('\n');

const body = (ai.body_markdown || '').trim() + '\n';
const fileContent = frontmatter + '\n' + body;

return [
  {
    json: {
      slug,
      filePath: 'conen-blog/src/content/blog/' + slug + '.md',
      fileContent,
      commitMessage: 'blog: új draft – ' + (ai.title || source.sourceTitle),
      guid: source.guid
    }
  }
];

// Sikeres commit után elmentjük a guid-ot, hogy ne dolgozzuk fel újra.
const guid = $('.md fájl összeállítás').first().json.guid;
const store = $getWorkflowStaticData('global');
store.seenGuids = store.seenGuids || [];
if (guid && !store.seenGuids.includes(guid)) {
  store.seenGuids.push(guid);
  // memóriahatár: csak az utolsó 500-at tartjuk meg
  if (store.seenGuids.length > 500) {
    store.seenGuids = store.seenGuids.slice(-500);
  }
}
return [{ json: { ok: true, savedGuid: guid, totalSeen: store.seenGuids.length } }];
